module.exports=[54546,a=>{"use strict";var b=a.i(72507),c=a.i(91920),d=a.i(69622);let e=[{question:"Wat is CoachScribe?",answer:"CoachScribe is een AI-ondersteunde tool voor coaches om gesprekken eenvoudig op te nemen, automatisch te laten samenvatten en overzichtelijke, bruikbare rapportages te maken. Het helpt je om minder tijd kwijt te zijn aan administratie, terwijl je wel grip houdt op de inhoud, nuance en context van al je sessies."},{question:"Is CoachScribe veilig?",answer:"Ja. CoachScribe is veilig ingericht met sterke technische en organisatorische maatregelen om jouw gegevens te beschermen. Alle data wordt versleuteld opgeslagen en verwerkt binnen de Europese Unie, in overeenstemming met de AVG. Jouw gegevens worden niet gebruikt om AI-modellen te trainen en alleen bewaard zolang dat functioneel nodig is."},{question:"Worden er AI modellen getraind met mijn informatie?",answer:"Nee. Jouw gegevens worden niet gebruikt om AI-modellen te trainen of te verbeteren. Ze worden uitsluitend verwerkt om de functionaliteiten van CoachScribe voor jou uit te voeren."},{question:"Voor wie is CoachScribe bedoeld?",answer:"CoachScribe is specifiek ontwikkeld voor loopbaan- en re-integratieprofessionals die werken met meerdere clienten en trajecten. Het helpt je om sessies gestructureerd vast te leggen, voortgang bij te houden en verslaglegging richting opdrachtgevers of UWV eenvoudiger te maken."},{question:"Is CoachScribe een vervanging voor een menselijke coach?",answer:"Nee. CoachScribe ondersteunt coaches met automatisering van taken zoals notities maken en verslaglegging, maar vervangt nooit het menselijke oordeel, de contextbegrip of de relatie tussen coach en client."},{question:"Kan ik niet gewoon ChatGPT gebruiken?",answer:"Nee. ChatGPT is een algemene AI en beschikt niet over de functionaliteit voor sessie opname, gestructureerde verslaglegging of AVG-proof beheer van clientgegevens, waardoor het niet geschikt is voor dit soort toepassingen. Daarnaast is CoachScribe ontworpen speciaal voor coaches en kan het dus een stuk gerichter te werk gaan."}];function f(){let[a,f]=(0,c.useState)(null);return(0,b.jsx)(d.default,{className:"bg-[#F8F9F9]",contentClassName:"md:pt-20 md:pb-20",children:(0,b.jsxs)("div",{className:"flex w-full flex-col gap-8",children:[(0,b.jsx)("h2",{className:"text-3xl font-semibold text-[#1D0A00] md:text-5xl xl:text-6xl",children:"Veel gestelde vragen"}),(0,b.jsx)("div",{className:"w-full border-y border-black/40",children:e.map((c,d)=>{let e=a===c.question;return(0,b.jsxs)("div",{className:0===d?"":"border-t border-black/40",children:[(0,b.jsxs)("button",{type:"button","aria-expanded":e,"aria-controls":`faq-answer-${d}`,onClick:()=>f(a=>a===c.question?null:c.question),className:"flex w-full cursor-pointer items-center justify-between gap-6 py-5 text-left text-[#1D0A00] transition-colors hover:text-[#BD0265]",children:[(0,b.jsx)("span",{className:"text-base font-semibold md:text-xl",children:c.question}),(0,b.jsx)("span",{"aria-hidden":"true",className:`shrink-0 ${e?"rotate-45":""}`,children:(0,b.jsxs)("svg",{xmlns:"http://www.w3.org/2000/svg",width:"24",height:"24",viewBox:"0 0 24 24",fill:"none",children:[(0,b.jsx)("path",{d:"M6 12H18",stroke:"#1D0A00",strokeWidth:"2",strokeLinecap:"round",strokeLinejoin:"round"}),(0,b.jsx)("path",{d:"M12 18V6",stroke:"#1D0A00",strokeWidth:"2",strokeLinecap:"round",strokeLinejoin:"round"})]})})]}),(0,b.jsx)("div",{id:`faq-answer-${d}`,className:e?"block":"hidden",children:(0,b.jsx)("p",{className:"pb-5 text-base font-normal leading-relaxed text-[#1D0A00]",children:c.answer})})]},c.question)})})]})})}a.s(["default",()=>f])}];

